import styled from 'styled-components';
 
 export const Page = styled.div`
  min-height: 100vh;
  min-width: 100vw;
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  background-color: peachpuff;
  opacity: 0.6;
`;

export const Corridor = styled.img`
  padding: 1vh;
  height: 85.5vh;
`

export function addSpaces (word) {
  const string = word.split();
  word = "";
  string.forEach(letter => {
    if (letter === " ") {
      word += " ".repeat(3)
    } else {
      word += letter + " "
    }
  });
}
